SELECT id, user_id userId, coin_type coinType, change_balance changeBalance, before_balance beforeBalance, after_balance afterBalance, serial_code serialCode, source_code sourceCode, source_type sourceType, remark, create_time createTime FROM t_user_money_log WHERE active_flag = 1 and user_id = #{userId}
and coin_type = #{coinType}
and source_type = #{sourceType}
ORDER BY id desc



     and user_id = #{userId}
